  1	import React, { FC } from 'react';
  2	
  3	import { Button, TextInput, Tooltip } from '@patternfly/react-core';
  4	import { MinusCircleIcon, PlusCircleIcon } from '@patternfly/react-icons';
  5	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
  6	
  7	type LabelSelectorEditorProps = {
  8	  labelSelectorPairs: string[][];
  9	  onLastItemRemoved: () => void;
 10	  updateParentData: (newLabelSelectorPairs: string[][]) => void;
 11	};
 12	
 13	const LabelSelectorEditor: FC<LabelSelectorEditorProps> = ({
 14	  labelSelectorPairs,
 15	  onLastItemRemoved,
 16	  updateParentData,
 17	}) => {
 18	  const { t } = useNetworkingTranslation();
 19	
 20	  const onChange = (label: string, selector: string, index: number) => {
 21	    const newPairs = [...labelSelectorPairs];
 22	
 23	    newPairs[index] = [label, selector];
 24	    updateParentData(newPairs);
 25	  };
 26	
 27	  const onRemove = (index: number) => {
 28	    updateParentData(labelSelectorPairs.slice(index, index + 1));
 29	
 30	    if (labelSelectorPairs.length === 1) onLastItemRemoved();
 31	  };
 32	
 33	  const onAddPair = () => {
 34	    updateParentData([...labelSelectorPairs, ['', '']]);
 35	  };
 36	
 37	  return (
 38	    <>
 39	      <div className="row pairs-list__heading">
 40	        <div className="col-xs-5 text-secondary text-uppercase" id="editor-label-header">
 41	          {t('Label')}
 42	        </div>
 43	        <div className="col-xs-5 text-secondary text-uppercase" id="editor-selector-header">
 44	          {t('Selector')}
 45	        </div>
 46	        <div className="col-xs-1 co-empty__header" />
 47	      </div>
 48	      {labelSelectorPairs.map((labelSelectorPair, index) => {
 49	        return (
 50	          <div className="row pairs-list__row" key={index}>
 51	            <div className="col-xs-5 pairs-list__value-pair-field">
 52	              <TextInput
 53	                aria-labelledby="editor-label-header"
 54	                id={`${index}-serial`}
 55	                onChange={(_, value) => onChange(value, labelSelectorPair[1], index)}
 56	                type="text"
 57	                value={labelSelectorPair[0]}
 58	              />
 59	            </div>
 60	            <div className="col-xs-5 pairs-list__name-field">
 61	              <TextInput
 62	                aria-labelledby="editor-selector-header"
 63	                id={`${index}-serial`}
 64	                onChange={(_, value) => onChange(labelSelectorPair[0], value, index)}
 65	                type="text"
 66	                value={labelSelectorPair[1]}
 67	              />
 68	            </div>
 69	            <div className="col-xs-1 pairs-list__action">
 70	              <Tooltip content={t('Remove')}>
 71	                <Button
 72	                  className="pairs-list__span-btns"
 73	                  data-test-id="pairs-list__delete-from-btn"
 74	                  onClick={() => onRemove(index)}
 75	                  type="button"
 76	                  variant="plain"
 77	                >
 78	                  <MinusCircleIcon className="pairs-list__side-btn pairs-list__delete-icon" />
 79	                  <span className="sr-only">{t('Delete')}</span>
 80	                </Button>
 81	              </Tooltip>
 82	            </div>
 83	          </div>
 84	        );
 85	      })}
 86	      <div className="row">
 87	        <div className="col-xs-12">
 88	          <Button
 89	            className="pf-m-link--align-left"
 90	            onClick={onAddPair}
 91	            type="button"
 92	            variant="link"
 93	          >
 94	            <PlusCircleIcon /> {t('Add label')}
 95	          </Button>
 96	        </div>
 97	      </div>
 98	    </>
 99	  );
100	};
101	
102	export default LabelSelectorEditor;

